// Auto-generated: Paper Mono subset (0-9, A-Z, a-z, space) as base64 for
// resvg-wasm text shaping in the OG image Pages Function (functions/og.ts).
//
// Paper Mono is a variable font (wght 100-800, default 400). resvg-wasm ignores
// the wght axis and always renders the font's DEFAULT instance, so a plain subset
// renders the OG brand at 400 even though the SVG asks for font-weight 700. We
// therefore re-default the variable font to wght=700 (keeping it variable; the
// instancer's pin-to-static path corrupts glyf for resvg) before subsetting, so
// both the "IntD" brand and the dynamic ?p= number render bold.
//
// Regenerate when the font or the rendered charset changes:
//   python3 -c "from fontTools.ttLib import TTFont; \
//     from fontTools.varLib.instancer import instantiateVariableFont as I; \
//     f=TTFont('public/fonts/PaperMono[wght].woff2'); \
//     I(f,{'wght':(100,700,800)},inplace=True,updateFontNames=False); \
//     f.save('/tmp/PaperMono-default700.woff2')"
//   pyftsubset /tmp/PaperMono-default700.woff2 \
//     --output-file=src/lib/paper-mono-subset.woff2 --flavor=woff2 \
//     --layout-features='' --no-hinting --desubroutinize \
//     --unicodes=U+0020,U+0030-0039,U+0041-005A,U+0061-007A
//   node -e 'const fs=require("fs");const b=fs.readFileSync("src/lib/paper-mono-subset.woff2");fs.writeFileSync("src/lib/paper-mono-font.ts",`export const PAPER_MONO_WOFF2_BASE64 =\n  "${b.toString("base64")}"\n`)'
//   (then restore this comment header)
export const PAPER_MONO_WOFF2_BASE64 =
  ""
